{
    int a,b,c,d[100],i=1,e=0;
    scanf("%d %d %d",&a,&b,&c);
    d[i]=a+b*c;i++;
    d[i]=a*(b+c);i++;
    d[i]=a*b*c;i++;
    d[i]=(a+b)*c;i++;
    d[i]=a+b+c;
    for(i=1;i<=5;i++)
